const source = $('Refund Form Webhook').first()?.json ?? $('When clicking \'Execute workflow\'').first()?.json ?? $input.first()?.json ?? {};
const query = source.query ?? source;
const settings = $('Load Global Settings').first()?.json ?? {};
const headers = source.headers ?? {};
const rows = $input.all().map((item) => item.json ?? {});
const directory = rows.filter((entry) => entry.row_type === 'person' && String(entry.name ?? '').trim());
const membershipCategories = rows.filter((entry) => entry.row_type === 'membership' && String(entry.membership ?? '').trim());
const clean = (value) => value === null || value === undefined ? '' : String(value).trim();
const escapeHtml = (value) => clean(value)
  .replace(/&/g, '&amp;')
  .replace(/</g, '&lt;')
  .replace(/>/g, '&gt;')
  .replace(/\"/g, '&quot;')
  .replace(/'/g, '&#39;');
const deriveBaseUrl = (headers, fallback) => {
  const forwardedProto = clean(headers['x-forwarded-proto']);
  const forwardedHost = clean(headers['x-forwarded-host']);
  const host = forwardedHost || clean(headers.host);
  const forwardedPort = clean(headers['x-forwarded-port']);
  if (!host) return fallback;
  const proto = forwardedProto || 'http';
  let authority = host;
  if (forwardedPort && !authority.includes(':')) {
    const isDefaultPort = (proto === 'http' && forwardedPort === '80') || (proto === 'https' && forwardedPort === '443');
    if (!isDefaultPort) authority = `${authority}:${forwardedPort}`;
  }
  return `${proto}://${authority}`;
};
const parseBoolean = (value) => ['1', 'true', 'yes', 'on'].includes(clean(value).toLowerCase());
const fallbackBaseUrl = clean(settings.n8n_base_url) || 'http://n8n:5678';
const n8nBaseUrl = deriveBaseUrl(headers, fallbackBaseUrl);
const actionUrl = `${n8nBaseUrl}/webhook/add-refund`;
const returnUrl = clean(query.return_url) || `${n8nBaseUrl}/webhook/refunds`;
const name = clean(query.name);
const refundFor = clean(query.refund_for ?? query.for_name ?? query.for);
const reason = clean(query.reason);
const membership = clean(query.membership);
const amount = clean(query.amount);
const fromDate = clean(query.from_date ?? query.fromDate);
const toDate = clean(query.to_date ?? query.toDate);
const waiveAdminFee = parseBoolean(query.waive_admin_fee ?? query.waiveAdminFee);
const errorMessage = clean(query.error);
const directoryOptions = directory.map((entry) => {
  const label = entry.email ? `${entry.name} <${entry.email}>` : entry.name;
  return `<option value="${escapeHtml(label)}"></option>`;
}).join('');
const membershipOptions = membershipCategories.map((entry) => `<option value="${escapeHtml(entry.membership)}"></option>`).join('');
const directoryJson = JSON.stringify(directory).replace(/</g, '\\u003c');
const html = `<!doctype html>
<html lang="en">
<head>
  <meta charset="utf-8">
  <meta name="viewport" content="width=device-width, initial-scale=1">
  <title>Create Refund Request</title>
  <style>
    :root { color-scheme: light; --bg: #f7f8fc; --panel: #ffffff; --ink: #243447; --muted: #66788a; --line: #d9e2ec; --accent: #2f80d8; --accent-dark: #2567ad; --danger: #b93a3a; --soft: #f8fbff; --success-soft: #edf8f2; }
    * { box-sizing: border-box; }
    body { margin: 0; padding: 24px; min-height: 100vh; font-family: Lato, 'Helvetica Neue', Arial, sans-serif; background: linear-gradient(180deg, #fbfcfe 0%, var(--bg) 100%); color: var(--ink); }
    .wrap { max-width: 980px; margin: 0 auto; background: var(--panel); border: 1px solid var(--line); border-radius: 18px; padding: 28px; box-shadow: 0 18px 40px rgba(36, 52, 71, 0.08); }
    h1 { margin: 0 0 10px; font-size: 32px; line-height: 1.1; }
    p { margin: 0 0 20px; color: var(--muted); }
    form { display: grid; gap: 18px; }
    .grid { display: grid; gap: 16px; grid-template-columns: repeat(auto-fit, minmax(260px, 1fr)); }
    .search-row, .calc-panel { display:grid; gap:16px; grid-template-columns: repeat(auto-fit, minmax(260px, 1fr)); padding:16px; border:1px solid var(--line); border-radius:14px; background: var(--soft); }
    .calc-panel { grid-template-columns: minmax(0, 1.2fr) minmax(280px, 0.8fr); align-items: start; }
    label { display: block; font-weight: 700; margin-bottom: 6px; }
    input, textarea { width: 100%; border: 1px solid var(--line); border-radius: 10px; padding: 10px 12px; font: inherit; color: var(--ink); background: #fff; }
    textarea { min-height: 96px; resize: vertical; }
    .checkbox-row { display:flex; align-items:flex-start; gap:12px; padding:14px 16px; border:1px solid var(--line); border-radius:14px; background:#fff; }
    .checkbox-row input { width:18px; height:18px; margin-top:2px; accent-color: var(--accent); }
    .checkbox-row label { margin:0; }
    .checkbox-row .subtle { margin:4px 0 0; font-size:14px; color: var(--muted); }
    .calculation-summary { border:1px solid var(--line); border-radius:14px; padding:16px; background:#fff; }
    .calculation-summary h2 { margin:0 0 12px; font-size:18px; }
    .calc-grid { display:grid; grid-template-columns: repeat(2, minmax(0, 1fr)); gap:12px 16px; }
    .calc-grid div { border:1px solid var(--line); border-radius:12px; padding:12px; background:#fbfcfe; }
    .calc-grid span { display:block; font-size:12px; text-transform:uppercase; letter-spacing:.05em; color: var(--muted); font-weight:700; margin-bottom:4px; }
    .calc-grid strong { display:block; font-size:18px; }
    .calc-formula, .calc-message { margin-top:14px; font-size:14px; line-height:1.6; color: var(--muted); }
    .calc-message.error-text { color: var(--danger); font-weight:700; }
    .actions { display: flex; gap: 12px; align-items: center; flex-wrap: wrap; }
    button, .secondary { appearance: none; border: 0; border-radius: 999px; padding: 12px 18px; font: inherit; font-weight: 700; cursor: pointer; text-decoration: none; }
    button { color: #fff; background: linear-gradient(135deg, var(--accent) 0%, var(--accent-dark) 100%); }
    .secondary { color: var(--ink); background: #eef2f7; border: 1px solid var(--line); }
    .note { font-size: 14px; color: var(--muted); }
    .error { margin: 0 0 20px; padding: 14px 16px; border-radius: 14px; background: #fdecec; color: var(--danger); font-weight: 700; }
    @media (max-width: 720px) { body { padding: 14px; } .wrap { padding: 18px; } .calc-panel { grid-template-columns: 1fr; } .calc-grid { grid-template-columns: 1fr; } }
  </style>
</head>
<body>
  <div class="wrap">
    <h1>Create Refund Request</h1>
    <p>Create a refund case and return to the refunds landing page. Search fields help populate the names, but you can always type directly into the actual requestor and member fields.</p>
    ${errorMessage ? `<div class="error">${escapeHtml(errorMessage)}</div>` : ''}
    <form action="${actionUrl}" method="post">
      <input type="hidden" name="created_by" value="refund_form_webhook">
      <input type="hidden" name="return_url" value="${escapeHtml(returnUrl)}">
      <div class="search-row">
        <div>
          <label for="requestor_search">Search Requestor By Name Or Email</label>
          <input id="requestor_search" type="search" list="member-directory" placeholder="Start typing a name or email" onchange="applyDirectoryMatch(this.value, 'name')">
        </div>
        <div>
          <label for="member_search">Search Member By Name Or Email</label>
          <input id="member_search" type="search" list="member-directory" placeholder="Start typing a name or email" onchange="applyDirectoryMatch(this.value, 'refund_for')">
        </div>
        <datalist id="member-directory">${directoryOptions}</datalist>
      </div>
      <div class="grid">
        <div>
          <label for="name">Requestor Name</label>
          <input id="name" name="name" type="text" value="${escapeHtml(name)}" required>
        </div>
        <div>
          <label for="refund_for">Member Name</label>
          <input id="refund_for" name="refund_for" type="text" value="${escapeHtml(refundFor)}" required>
        </div>
      </div>
      <div class="grid">
        <div>
          <label for="reason">Reason</label>
          <input id="reason" name="reason" type="text" list="reason-options" value="${escapeHtml(reason)}" required>
          <datalist id="reason-options">
            <option value="Injured"></option>
            <option value="Deceased"></option>
            <option value="Membership Cancelled"></option>
            <option value="Other"></option>
          </datalist>
        </div>
        <div>
          <label for="membership">Membership</label>
          <input id="membership" name="membership" type="text" list="membership-categories" value="${escapeHtml(membership)}" placeholder="Search or type a membership category" required>
          <datalist id="membership-categories">${membershipOptions}</datalist>
        </div>
      </div>
      <div class="grid">
        <div>
          <label for="amount">Amount Paid</label>
          <input id="amount" name="amount" type="number" min="0" step="0.01" value="${escapeHtml(amount)}" required>
        </div>
        <div>
          <label for="from_date">From Date</label>
          <input id="from_date" name="from_date" type="date" value="${escapeHtml(fromDate)}" required>
        </div>
        <div>
          <label for="to_date">To Date</label>
          <input id="to_date" name="to_date" type="date" value="${escapeHtml(toDate)}" required>
        </div>
      </div>
      <div class="checkbox-row">
        <input id="waive_admin_fee" name="waive_admin_fee" type="checkbox" value="1"${waiveAdminFee ? ' checked' : ''}>
        <div>
          <label for="waive_admin_fee">Waive admin fee and refund the full pro-rated amount</label>
          <p class="subtle">Unchecked uses the standard calculation with one month retained as the admin fee. Checked removes that deduction.</p>
        </div>
      </div>
      <section class="calc-panel">
        <div>
          <h2>Live Calculation</h2>
          <p class="note">This preview uses the same month-based logic as the refund workflow that writes to <code>public.refunds</code>.</p>
          <div id="calculation-message" class="calc-message"></div>
          <div id="calculation-formula" class="calc-formula"></div>
        </div>
        <div class="calculation-summary">
          <h2>Calculated Refund</h2>
          <div class="calc-grid">
            <div><span>Calendar Months</span><strong id="calc-months">-</strong></div>
            <div><span>Admin Fee</span><strong id="calc-admin-fee">-</strong></div>
            <div><span>Refundable Months</span><strong id="calc-refundable-months">-</strong></div>
            <div><span>Refund Amount</span><strong id="calc-refund">-</strong></div>
          </div>
        </div>
      </section>
      <div class="actions">
        <button type="submit">Create Refund Request</button>
        <a class="secondary" href="${escapeHtml(returnUrl)}">Back To Refunds</a>
        <button type="button" class="secondary" onclick="window.close()">Close</button>
        <span class="note">New refunds are created with status <strong>New Request</strong>. Request-bank-details and treasury emails are sent later from the refunds landing page.</span>
      </div>
    </form>
  </div>
  <script>
    const memberDirectory = ${directoryJson};
    function applyDirectoryMatch(value, targetId) {
      const needle = String(value || '').trim().toLowerCase();
      if (!needle) return;
      const match = memberDirectory.find((entry) => {
        const name = String(entry.name || '').trim();
        const email = String(entry.email || '').trim();
        const combined = email ? (name + ' <' + email + '>') : name;
        return combined.toLowerCase() === needle || name.toLowerCase() === needle || email.toLowerCase() === needle;
      });
      if (match) document.getElementById(targetId).value = match.name;
    }
    function parseIsoDate(value) {
      const raw = String(value || '').trim();
      const match = raw.match(/^(\\d{4})-(\\d{2})-(\\d{2})$/);
      if (!match) return null;
      const year = Number.parseInt(match[1], 10);
      const month = Number.parseInt(match[2], 10);
      const day = Number.parseInt(match[3], 10);
      if (!Number.isInteger(year) || !Number.isInteger(month) || !Number.isInteger(day)) return null;
      if (month < 1 || month > 12 || day < 1 || day > 31) return null;
      return { year, month, day, iso: raw };
    }
    function formatMoney(value) {
      const rounded = Math.round((Number(value) + Number.EPSILON) * 100) / 100;
      const text = Number.isInteger(rounded) ? String(rounded) : rounded.toFixed(2).replace(/\\.00$/, '').replace(/(\\.\\d)0$/, '$1');
      return '£' + text;
    }
    function calculateRefund() {
      const amount = Number.parseFloat(String(document.getElementById('amount').value || '').replace(/,/g, ''));
      const fromDate = parseIsoDate(document.getElementById('from_date').value);
      const toDate = parseIsoDate(document.getElementById('to_date').value);
      const waiveAdminFee = document.getElementById('waive_admin_fee').checked;
      if (!Number.isFinite(amount) || amount < 0) {
        return { ok: false, message: 'Enter a valid amount paid to see the refund calculation.' };
      }
      if (!fromDate || !toDate) {
        return { ok: false, message: 'Choose both From Date and To Date to calculate the refund.' };
      }
      const fromMonthNumber = (fromDate.year * 12) + fromDate.month;
      const toMonthNumber = (toDate.year * 12) + toDate.month;
      const fromDayNumber = Date.UTC(fromDate.year, fromDate.month - 1, fromDate.day);
      const toDayNumber = Date.UTC(toDate.year, toDate.month - 1, toDate.day);
      if (toDayNumber < fromDayNumber) {
        return { ok: false, message: 'To Date must be on or after From Date.' };
      }
      const months = (toMonthNumber - fromMonthNumber) + 1;
      const adminFeeMonths = waiveAdminFee ? 0 : 1;
      const refundableMonths = Math.max(months - adminFeeMonths, 0);
      const refund = Math.round((amount * refundableMonths) / 12);
      const formula = waiveAdminFee
        ? formatMoney(amount) + ' * ' + months + '/12 months = ' + formatMoney(refund)
        : formatMoney(amount) + ' * (' + months + '-1)/12 months = ' + formatMoney(refund);
      return { ok: true, months, adminFeeMonths, refundableMonths, refund, formula, waiveAdminFee };
    }
    function updateCalculationPreview() {
      const result = calculateRefund();
      const monthsEl = document.getElementById('calc-months');
      const adminFeeEl = document.getElementById('calc-admin-fee');
      const refundableEl = document.getElementById('calc-refundable-months');
      const refundEl = document.getElementById('calc-refund');
      const messageEl = document.getElementById('calculation-message');
      const formulaEl = document.getElementById('calculation-formula');
      if (!result.ok) {
        monthsEl.textContent = '-';
        adminFeeEl.textContent = '-';
        refundableEl.textContent = '-';
        refundEl.textContent = '-';
        messageEl.textContent = result.message;
        messageEl.className = 'calc-message error-text';
        formulaEl.textContent = '';
        return;
      }
      monthsEl.textContent = String(result.months);
      adminFeeEl.textContent = result.waiveAdminFee ? 'Waived' : '1 month';
      refundableEl.textContent = String(result.refundableMonths);
      refundEl.textContent = formatMoney(result.refund);
      messageEl.textContent = result.waiveAdminFee
        ? 'Admin fee waived. The full pro-rated amount will be used when the refund record is created.'
        : 'Standard admin fee applies. One month is retained before the refund is calculated.';
      messageEl.className = 'calc-message';
      formulaEl.textContent = 'Formula used: ' + result.formula;
    }
    ['amount', 'from_date', 'to_date', 'waive_admin_fee'].forEach((id) => {
      document.getElementById(id).addEventListener('input', updateCalculationPreview);
      document.getElementById(id).addEventListener('change', updateCalculationPreview);
    });
    updateCalculationPreview();
  </script>
</body>
</html>`;
return [{ json: { html } }];
